class Tactic:
    def __init__(self):
        self.goal = (22, 18)  # cover position
    def tick(self, me, world):
        if me.pos != self.goal:
            path = world.path(self.goal)
            if path:
                return me.move_toward(path[1])
            else:
                return me.move_toward(self.goal)
        if me.cooldown == 0:
            candidates = [e for e in world.visible_enemies() if me.distance_to(e) <= me.range]
            if candidates:
                target = min(candidates, key=lambda e: (e.type != "mortar", e.type != "medic", e.hp, e.id))
                return me.attack(target)
        return me.move_toward(world.enemy_spawn)

